import { FACTIONS, MAJOR_FACTIONS, MINOR_FACTIONS } from './factions.js';
import { LOCATIONS, LOCATION_MAP } from './locations.js';

function stats(base, i = 0) {
  return {
    perang: Math.min(99, base.perang + (i % 7) * 2),
    intelek: Math.min(99, base.intelek + (i % 5) * 2),
    politik: Math.min(99, base.politik + (i % 6) * 2),
    karisma: Math.min(99, base.karisma + (i % 4) * 3),
  };
}

function icon(seed) {
  return {
    ...seed,
    kind: 'iconic',
    location: LOCATION_MAP[seed.locationId]?.name ?? seed.locationId,
  };
}

