function generateSupportCharacters() {
  const list = [...ICONIC_CHARACTERS];
  const byFaction = Object.groupBy ? Object.groupBy(list, (c) => c.faction) : list.reduce((acc, c) => ((acc[c.faction] ||= []).push(c), acc), {});

  const fixedMinorCounts = { orc: 9, demon: 8, ancient: 8, eldara: 8, rust: 8, moon: 9 };

  for (const factionId of MAJOR_FACTIONS) {
    const existing = (byFaction[factionId] || []).length;
    const need = Math.max(0, 30 - existing);
    const locs = LOCATIONS.filter((l) => l.faction === factionId);
    const names = SUPPORT_NAME_POOLS[factionId];
    const roles = SUPPORT_ROLES[factionId];
    for (let i = 0; i < need; i++) {
      const loc = locs[i % locs.length];
      const baseName = names[i % names.length];
      list.push({
        id: `${factionId}-support-${i+1}`,
        faction: factionId,
        kind: 'support',
        name: `${baseName} ${String.fromCharCode(65 + (i % 26))}`,
        role: roles[i % roles.length],
        age: 19 + ((i * 5) % 41),
        locationId: loc.id,
        location: loc.name,
        stats: stats({ perang: 42 + (i % 5) * 6, intelek: 40 + (i % 5) * 7, politik: 35 + (i % 4) * 8, karisma: 41 + (i % 5) * 6 }, i),
        bio: `${baseName} adalah tokoh pendukung penting di ${FACTIONS[factionId].name}, terlibat dalam pekerjaan lapis kedua yang membuat faksi tetap berjalan sehari-hari.`,
        drama: `Meski bukan pusat legenda, tokoh seperti ini sering menjadi penghubung rahasia, saksi, atau pemantik konflik lokal di wilayah ${loc.name}.`,
        secret: 'Memegang satu informasi, utang, atau hubungan gelap yang bisa menaikkan perannya sewaktu-waktu.',
        connections: ['Terhubung dengan lingkar tokoh besar di faksinya', 'Dapat berkembang menjadi pemain penting bila cerita diteruskan'],
      });
    }
  }

  for (const factionId of MINOR_FACTIONS) {
    const target = fixedMinorCounts[factionId] || 8;
    const locs = LOCATIONS.filter((l) => l.faction === factionId);
    const names = SUPPORT_NAME_POOLS[factionId];
    const roles = SUPPORT_ROLES[factionId];
    for (let i = 0; i < target; i++) {
      const loc = locs[i % locs.length];
      const baseName = names[i % names.length];
      list.push({
        id: `${factionId}-support-${i+1}`,
        faction: factionId,
        kind: 'support',
        name: `${baseName} ${i+1}`,
        role: roles[i % roles.length],
        age: 24 + ((i * 6) % 50),
        locationId: loc.id,
        location: loc.name,
        stats: stats({ perang: 47 + (i % 5) * 5, intelek: 48 + (i % 4) * 6, politik: 32 + (i % 3) * 7, karisma: 38 + (i % 4) * 6 }, i),
        bio: `Tokoh penting tingkat menengah di ${FACTIONS[factionId].name}.`,
        drama: 'Keberadaannya memperumit keseimbangan kekuatan regional walau belum seikonik pemain utama.',
        secret: 'Menyimpan agenda sampingan yang belum sepenuhnya diketahui pimpinannya sendiri.',
        connections: ['Aktif di wilayah faksi kecil', 'Potensial masuk konflik besar'],
      });
    }
  }

  return list;
}

export const ALL_CHARACTERS = generateSupportCharacters();

export function charactersByFaction(factionId) {
  return ALL_CHARACTERS.filter((c) => c.faction === factionId);
}
